 989→  _render() {
 990→    if (!this._config || !this._hass || !this._root) {
 991→      return;
 992→    }
 993→
 994→    this._stateObj = this._hass.states[this._config.entity];
 995→    if (!this._stateObj) {
 996→      this._root.innerHTML = `
 997→        <ha-card>
 998→          <div class="empty">Entity not found: <code>${this._escape(this._config.entity)}</code></div>
 999→        </ha-card>
1000→      `;
1001→      return;
1002→    }
1003→
1004→    const attrs = this._stateObj.attributes || {};
1005→    const rawWeeks = Array.isArray(attrs.weeks) ? attrs.weeks : [];
1006→    const members = Array.isArray(attrs.members) ? attrs.members : [];
1007→    const memberMap = this._memberMap(members);
1008→
1009→    const activeWeekStarts = new Set(rawWeeks.map((row) => String(row.week_start || "")));
1010→    for (const weekStart of [...this._pendingDoneWeeks]) {
1011→      if (!activeWeekStarts.has(weekStart)) {
1012→        this._pendingDoneWeeks.delete(weekStart);
1013→      }
1014→    }
1015→    for (const weekStart of [...this._pendingSwapWeeks]) {
1016→      if (!activeWeekStarts.has(weekStart)) {
1017→        this._pendingSwapWeeks.delete(weekStart);
1018→      }
1019→    }
1020→    for (const weekStart of [...this._optimisticWeekPatches.keys()]) {
1021→      if (!activeWeekStarts.has(weekStart)) {
1022→        this._optimisticWeekPatches.delete(weekStart);
1023→      }
1024→    }
1025→
1026→    const rawByWeekStart = new Map(rawWeeks.map((row) => [String(row.week_start || ""), row]));
1027→    for (const [weekStart, patch] of [...this._optimisticWeekPatches.entries()]) {
1028→      const rawRow = rawByWeekStart.get(weekStart);
1029→      if (!rawRow) {
1030→        this._optimisticWeekPatches.delete(weekStart);
1031→        continue;
1032→      }
1033→      const patchApplied = Object.entries(patch).every(
1034→        ([key, value]) => this._normalizePatchValue(rawRow?.[key]) === value
1035→      );
1036→      if (patchApplied) {
1037→        this._optimisticWeekPatches.delete(weekStart);
1038→      }
1039→    }
1040→
1041→    const weeksToShow = this._coerceWeeks(this._config.weeks);
1042→    const scheduleWeeks = rawWeeks
1043→      .slice()
1044→      .map((row) => {
1045→        const weekStart = String(row.week_start || "");
1046→        const patch = this._optimisticWeekPatches.get(weekStart);
1047→        if (!patch) {
1048→          return row;
1049→        }
1050→        return { ...row, ...patch };
1051→      })
1052→      .sort((a, b) => String(a.week_start || "").localeCompare(String(b.week_start || "")));
1053→    const weeks = scheduleWeeks.slice(0, weeksToShow);
1054→
1055→    const currentWeek =
1056→      scheduleWeeks.find((row) => row.is_current) || weeks[0] || scheduleWeeks[0] || null;
1057→    const currentStatus = String(currentWeek?.status || "pending");
1058→
1059→    const statusLabel =
1060→      currentStatus === "done" ? "Done" : currentStatus === "missed" ? "Missed" : "Pending";
1061→
1062→    const currentAssigneeName =
1063→      currentWeek?.assignee_name ||
1064→      (currentWeek?.assignee_member_id ? `Member ${currentWeek.assignee_member_id}` : "Unassigned");
1065→
1066→    const weekRows = weeks
1067→      .map((row, index) => {
1068→        const status = String(row?.status || "pending");
1069→        const isDone = status === "done";
1070→        const isMissed = status === "missed";
1071→        const isCurrent = !!row.is_current;
1072→        const isPrevious = !!row.is_previous;
1073→        const isPast = !!row.is_past;
